// ══════════════════════════════════════════
//  LVX Report Builder — Code Node (Fixed)
// ══════════════════════════════════════════

// 1) Read AI Agent output
const raw = items[0].json.output ?? '';
if (!raw) {
  return [{ json: { error: 'AI Agent output is empty', input: items[0].json } }];
}

let data;
try {
  // Strip markdown fences if any
  const clean = raw.replace(/```json|```/g, '').trim();
  // Extract first JSON object in case there's extra text
  const match = clean.match(/\{[\s\S]*\}/);
  data = JSON.parse(match ? match[0] : clean);
} catch (e) {
  return [{ json: { error: 'Failed to parse JSON: ' + e.message, raw: raw.substring(0, 500) } }];
}

const project    = data.project    ?? {};
const tasks      = Array.isArray(data.tasks)      ? data.tasks      : [];
const timesheets = Array.isArray(data.timesheets) ? data.timesheets : [];

// 2) Normalise stage_name — handle array [id, name] or plain string
const normalisedTasks = tasks.map((t, i) => {
  let stageName = '';
  if (Array.isArray(t.stage_id)) {
    stageName = String(t.stage_id[1] ?? '');
  } else if (typeof t.stage_name === 'string') {
    stageName = t.stage_name;
  } else if (typeof t.stage_id === 'string') {
    stageName = t.stage_id;
  }
  const isDone = /done|مكتمل|completed|closed/i.test(stageName);
  return {
    id:         t.id ?? i + 1,
    name:       t.name ?? '',
    stage_name: stageName || 'In Progress',
    status:     isDone ? 'Done' : 'In Progress'
  };
});

// 3) Normalise timesheets — handle employee_id as array [id, name]
const normalisedTS = timesheets.map((ts, i) => {
  let empName = '';
  if (Array.isArray(ts.employee_id)) {
    empName = String(ts.employee_id[1] ?? '');
  } else if (typeof ts.employee === 'string') {
    empName = ts.employee;
  } else if (typeof ts.employee_id === 'string') {
    empName = ts.employee_id;
  }
  let taskName = '';
  if (Array.isArray(ts.task_id)) {
    taskName = String(ts.task_id[1] ?? '');
  } else if (typeof ts.task === 'string') {
    taskName = ts.task;
  }
  return {
    id:       ts.id ?? i + 1,
    employee: empName,
    date:     ts.date ?? '',
    hours:    ts.unit_amount ?? ts.hours ?? 0,
    task:     taskName || ts.name || ''
  };
});

// 4) KPIs
const totalTasks      = normalisedTasks.length;
const doneTasks       = normalisedTasks.filter(t => t.status === 'Done').length;
const inProgressTasks = totalTasks - doneTasks;
const completionRate  = totalTasks ? Math.round((doneTasks / totalTasks) * 100) : 0;
const totalHours      = normalisedTS.reduce((s, ts) => s + Number(ts.hours || 0), 0);

// 5) Team summary
const empMap = {};
normalisedTS.forEach(ts => {
  const k = ts.employee || 'Unknown';
  if (!empMap[k]) empMap[k] = { hours: 0, sessions: 0 };
  empMap[k].hours    += Number(ts.hours || 0);
  empMap[k].sessions += 1;
});
const team = Object.entries(empMap).map(([name, d]) => ({
  name,
  initials: name.split(' ').map(w => w[0]).join('').substring(0, 2).toUpperCase(),
  hours:    Math.round(d.hours),
  sessions: d.sessions,
  pct:      totalHours ? Math.round((d.hours / totalHours) * 100) : 0
}));

// 6) Category grouping — group tasks by stage
const stageMap = {};
normalisedTasks.forEach(t => {
  const s = t.stage_name;
  if (!stageMap[s]) stageMap[s] = { done: 0, in_progress: 0 };
  if (t.status === 'Done') stageMap[s].done++;
  else stageMap[s].in_progress++;
});
const categories = Object.entries(stageMap).map(([name, d]) => ({
  name,
  total:       d.done + d.in_progress,
  done:        d.done,
  in_progress: d.in_progress,
  pct:         (d.done + d.in_progress) ? Math.round((d.done / (d.done + d.in_progress)) * 100) : 0,
  color:       d.in_progress === 0 ? '#16A34A' : '#D97706'
}));

// 7) Build task table rows (grouped by stage)
const tasksByStage = {};
normalisedTasks.forEach(t => {
  if (!tasksByStage[t.stage_name]) tasksByStage[t.stage_name] = [];
  tasksByStage[t.stage_name].push(t);
});

let taskRowsHtml = '';
Object.entries(tasksByStage).forEach(([stage, stageTasks]) => {
  taskRowsHtml += `<tr><td colspan="3" style="padding:0">
    <div style="background:#F7F6F2;padding:8px 16px;border-bottom:1px solid #E8E6DF;display:flex;align-items:center;gap:10px">
      <div style="width:8px;height:8px;border-radius:50%;background:#1A1916"></div>
      <span style="font-size:11px;font-weight:600;letter-spacing:1px;text-transform:uppercase">${stage}</span>
      <span style="font-size:11px;color:#888;margin-left:auto">${stageTasks.length} tasks</span>
    </div>
  </td></tr>`;
  stageTasks.forEach((t, i) => {
    const isDone   = t.status === 'Done';
    const pillBg   = isDone ? '#F0FDF4' : '#FFFBEB';
    const pillColor = isDone ? '#16A34A' : '#D97706';
    const pillBorder = isDone ? '#16A34A44' : '#D9770644';
    taskRowsHtml += `<tr>
      <td style="padding:10px 16px;color:#888;font-size:11px">${String(i + 1).padStart(2, '0')}</td>
      <td style="padding:10px 16px;font-weight:500;font-size:12.5px">${t.name}</td>
      <td style="padding:10px 16px;text-align:center">
        <span style="font-size:10px;font-weight:600;padding:3px 9px;border-radius:20px;background:${pillBg};color:${pillColor};border:1px solid ${pillBorder};text-transform:uppercase">${t.status}</span>
      </td>
    </tr>`;
  });
});

// 8) Timesheet rows
const tsRowsHtml = normalisedTS.map(ts => `
  <div style="display:grid;grid-template-columns:100px 140px 1fr 56px;border-bottom:1px solid #E8E6DF">
    <div style="padding:11px 14px;color:#888;font-size:12px">${ts.date}</div>
    <div style="padding:11px 14px;font-weight:500;font-size:12.5px">${ts.employee}</div>
    <div style="padding:11px 14px;color:#555;font-size:12px">${ts.task}</div>
    <div style="padding:11px 14px;font-weight:600;text-align:right;font-size:12.5px">${Number(ts.hours).toFixed(1)}h</div>
  </div>`
).join('');

// 9) Team cards
const teamColors = ['#1A1916', '#D97706', '#1D4ED8', '#DC2626'];
const teamCardsHtml = team.map((m, i) => `
  <div style="background:#fff;border:1px solid #E8E6DF;border-radius:8px;padding:18px 20px;display:flex;align-items:center;gap:14px">
    <div style="width:42px;height:42px;border-radius:50%;background:${teamColors[i % 4]};color:white;display:flex;align-items:center;justify-content:center;font-weight:800;font-size:13px;flex-shrink:0">${m.initials}</div>
    <div style="flex:1">
      <div style="font-weight:600;font-size:13px">${m.name}</div>
      <div style="font-size:11px;color:#888;margin-top:2px">${m.sessions} sessions</div>
      <div style="margin-top:8px;display:flex;align-items:center;gap:8px">
        <div style="flex:1;height:4px;background:#E8E6DF;border-radius:2px;overflow:hidden">
          <div style="height:100%;width:${m.pct}%;background:${teamColors[i % 4]};border-radius:2px"></div>
        </div>
        <span style="font-size:11px;color:#888;min-width:30px">${m.hours}h</span>
      </div>
    </div>
    <div style="font-weight:800;font-size:20px;min-width:44px;text-align:right">${m.pct}%</div>
  </div>`
).join('');

// 10) Category bars
const catBarsHtml = categories.map(c => `
  <div style="margin-bottom:16px">
    <div style="display:flex;justify-content:space-between;margin-bottom:5px">
      <span style="font-size:13px;font-weight:500;display:flex;align-items:center;gap:7px">
        <span style="width:8px;height:8px;border-radius:50%;background:${c.color};display:inline-block"></span>${c.name}
      </span>
      <span style="font-size:12px;color:#888">${c.done} Done &nbsp; ${c.in_progress} Active &nbsp; <b style="color:#1A1916">${c.pct}%</b></span>
    </div>
    <div style="height:6px;background:#E8E6DF;border-radius:3px;overflow:hidden">
      <div style="height:100%;width:${c.pct}%;background:${c.color};border-radius:3px"></div>
    </div>
  </div>`
).join('');

// 11) Chart data for Chart.js
const chartData = {
  done:        doneTasks,
  in_progress: inProgressTasks,
  cancelled:   0,
  categories,
  timesheets:  normalisedTS
};

// 12) Build full HTML
const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

const html = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1">
<title>LVX Report – ${project.name ?? 'Project'}</title>
<script src="https://cdnjs.cloudflare.com/ajax/libs/Chart.js/4.4.1/chart.umd.js"><\/script>
<style>
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700&family=Syne:wght@700;800&display=swap');
*{box-sizing:border-box;margin:0;padding:0}
body{font-family:'Inter',system-ui,sans-serif;background:#F7F6F2;color:#1A1916;font-size:13px;line-height:1.5;-webkit-font-smoothing:antialiased}
