.ts-head>div{padding:9px 14px;font-size:10px;font-weight:600;letter-spacing:1px;text-transform:uppercase;color:#888}
.team-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px;margin-bottom:20px}
