.print-btn{position:fixed;bottom:28px;right:28px;background:#1A1916;color:white;border:none;border-radius:8px;padding:12px 20px;font-size:12px;font-weight:600;cursor:pointer;box-shadow:0 4px 20px rgba(0,0,0,.2);z-index:99}
