<body>
<div class="page">

<!-- HEADER -->
<div class="report-header">
  <div style="display:flex;align-items:center;gap:14px">
    <img src="data:image/png;base64," class="logo-img" alt="LVX Logo">
    <div>
      <div class="brand-logo">LVX Smart Home Solutions</div>
      <div class="brand-sub">Smart Home &amp; Low-Voltage Systems</div>
    </div>
  </div>
  <div class="header-right">
    <strong>Project Status Report</strong><br>
    Client: ${project.partner ?? 'N/A'}<br>
    Date: ${today}<br>
    <span class="confidential">Confidential – For Client Use Only</span>
  </div>
</div>

<!-- TITLE -->
<div class="report-title">${project.name ?? 'Project'}</div>
<div class="report-sub">Smart Home &amp; Low-Voltage Systems</div>

<!-- KPIs -->
<div class="section">
  <div class="section-title">Executive Summary — Key Performance Indicators</div>
  <div class="kpi-grid">
    <div class="kpi-card"><div class="kpi-number">${totalTasks}</div><div class="kpi-label">Total Tasks</div></div>
    <div class="kpi-card"><div class="kpi-number kpi-green">${doneTasks}</div><div class="kpi-label">Completed</div></div>
    <div class="kpi-card"><div class="kpi-number kpi-amber">${inProgressTasks}</div><div class="kpi-label">In Progress</div></div>
    <div class="kpi-card"><div class="kpi-number">${completionRate}%</div><div class="kpi-label">Completion Rate</div></div>
  </div>
  <div class="summary-box">Overall project progress stands at <strong>${completionRate}% completion</strong> across ${totalTasks} tracked tasks. ${doneTasks} tasks have been successfully completed, while <strong>${inProgressTasks} tasks remain in progress</strong>. Total hours logged: <strong>${Math.round(totalHours)}h</strong> by ${team.length} engineer(s).</div>
</div>

<!-- CHARTS -->
<div class="charts-row">
  <div class="chart-card">
    <div class="chart-title">Task Status Overview</div>
    <div style="position:relative;height:200px"><canvas id="donutChart"></canvas></div>
  </div>
  <div class="chart-card">
    <div class="chart-title">Stage Breakdown</div>
    <div style="position:relative;height:200px"><canvas id="catChart"></canvas></div>
  </div>
</div>

<!-- CATEGORY ANALYSIS -->
<div class="section">
  <div class="section-title">Category-Level Analysis</div>
  ${catBarsHtml}
</div>

<!-- FULL TASK BREAKDOWN -->
<div class="section page-break">
  <div class="section-title">Full Task Breakdown — All ${totalTasks} Tasks</div>
  <table class="data-table">
    <thead><tr><th style="width:44px">#</th><th>Task Description</th><th style="width:130px;text-align:center">Status</th></tr></thead>
    <tbody>${taskRowsHtml}</tbody>
  </table>
</div>

<!-- TIMESHEETS -->
<div class="section page-break">
  <div class="section-title">Timesheets — ${project.name ?? 'Project'}</div>
  <p style="font-size:12px;color:#888;margin-bottom:14px">Total Hours: ${Math.round(totalHours)}h &nbsp;|&nbsp; ${team.length} Engineer(s)</p>
  <div class="ts-grid">
    <div class="ts-head"><div>Date</div><div>Employee</div><div>Task / Description</div><div style="text-align:right">Hrs</div></div>
    ${tsRowsHtml || '<div style="padding:16px 14px;color:#888">No timesheet entries found.</div>'}
  </div>
</div>

<!-- TEAM CONTRIBUTION -->
<div class="section">
  <div class="section-title">Team Contribution Summary</div>
  <div class="team-grid">${teamCardsHtml || '<p style="color:#888">No team data.</p>'}</div>
</div>

<!-- HOURS CHART -->
<div class="section">
  <div class="section-title">Hours by Day</div>
  <div class="chart-card" style="padding:20px">
    <div style="position:relative;height:180px"><canvas id="timelineChart"></canvas></div>
  </div>
</div>

<!-- RECOMMENDATIONS -->
<div class="section">
  <div class="section-title">Recommendations &amp; Next Steps</div>
  ${inProgressTasks > 0 ? `<div class="rec-card rec-warn"><div><div class="rec-title">Resolve ${inProgressTasks} in-progress task(s)</div><div class="rec-desc">Assign target completion dates and ensure daily logging in Odoo timesheets.</div></div></div>` : ''}
  ${completionRate === 100 ? `<div class="rec-card"><div><div class="rec-title">Project complete</div><div class="rec-desc">All tasks are done. Proceed to client sign-off and project closure.</div></div></div>` : ''}
  ${normalisedTasks.some(t => /complaint|complain/i.test(t.name)) ? `<div class="rec-card rec-urgent"><div><div class="rec-title">Address open client complaint</div><div class="rec-desc">A complaint task is still open. Escalate immediately to protect client satisfaction.</div></div></div>` : ''}
  <div class="rec-card rec-info"><div><div class="rec-title">Tag all tasks to proper categories</div><div class="rec-desc">Ensure all tasks are assigned to formal work packages in Odoo for cleaner reporting.</div></div></div>
</div>

<!-- FOOTER -->
<div class="report-footer">
  <span>Prepared by LVX Smart Home Solutions</span>
  <span>Issued: ${today}</span>
  <span>Confidential</span>
</div>

</div>
<button class="print-btn" onclick="window.print()">&#8659; Export PDF</button>

<script>
const CD = ${JSON.stringify(chartData)};

new Chart(document.getElementById('donutChart'),{
  type:'doughnut',
  data:{labels:['Done','In Progress'],datasets:[{data:[CD.done,CD.in_progress],backgroundColor:['#16A34A','#D97706'],borderWidth:0,hoverOffset:6}]},
  options:{responsive:true,maintainAspectRatio:false,cutout:'68%',plugins:{legend:{display:true,position:'bottom',labels:{color:'#888',font:{size:11,family:'Inter'},boxWidth:10,padding:14}}}}
});

new Chart(document.getElementById('catChart'),{
  type:'bar',
  data:{labels:CD.categories.map(c=>c.name),datasets:[{label:'Done',data:CD.categories.map(c=>c.done),backgroundColor:'#16A34A',borderRadius:4},{label:'In Progress',data:CD.categories.map(c=>c.in_progress),backgroundColor:'#D97706',borderRadius:4}]},
  options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:false}},scales:{x:{stacked:true,grid:{display:false},ticks:{color:'#888',font:{size:10}}},y:{stacked:true,grid:{color:'#E8E6DF'},ticks:{color:'#888',font:{size:10}}}}}
});

const dm={};const emps=[...new Set(CD.timesheets.map(t=>t.employee))];
CD.timesheets.forEach(t=>{if(!dm[t.date])dm[t.date]={};dm[t.date][t.employee]=(dm[t.date][t.employee]||0)+Number(t.hours);});
const ds=Object.keys(dm).sort();
const ec=['#1A1916','#D97706','#1D4ED8','#DC2626'];
new Chart(document.getElementById('timelineChart'),{
  type:'bar',
  data:{labels:ds,datasets:emps.map((e,i)=>({label:e,data:ds.map(d=>dm[d][e]||0),backgroundColor:ec[i%4],borderRadius:4}))},
  options:{responsive:true,maintainAspectRatio:false,plugins:{legend:{display:true,position:'bottom',labels:{color:'#888',font:{size:11,family:'Inter'},boxWidth:10,padding:14}}},scales:{x:{stacked:true,grid:{display:false},ticks:{color:'#888',font:{size:10}}},y:{stacked:true,grid:{color:'#E8E6DF'},ticks:{color:'#888',font:{size:10},callback:v=>v+'h'}}}}
});
<\/script>
</body>
</html>`;

return [{ json: { html, project_name: project.name, total_tasks: totalTasks, done_tasks: doneTasks, completion_rate: completionRate, total_hours: Math.round(totalHours) } }];
